using UnityEngine;

/// <summary>
/// Falha imediata quando uma variável global bool (GameVariables) tem o valor
/// "failValue". Genérico — cobre "o NPC defendido foi derrotado" (uma
/// Action_SetBoolVariable já existente marca isso ao acontecer), "armadilha
/// activada", "jogada errada do puzzle", etc., sem precisar de nenhum script
/// novo por desafio.
/// </summary>
[System.Serializable]
public class FailCondition_BoolVariable : ChallengeFailCondition
{
    [Tooltip("Nome da variável global (GameVariables). Se não existir, é tratada como tendo o valor por omissão (false).")]
    public string variableName;

    [Tooltip("Valor que, ao ser atingido pela variável, causa a falha imediata do desafio.")]
    public bool failValue = true;

    public override bool IsFailed()
    {
        bool actual = GameVariables.Instance != null && GameVariables.Instance.GetBool(variableName);
        return actual == failValue;
    }
}

/// <summary>
/// Falha imediata quando uma variável global int (GameVariables) cumpre
/// "comparison" face a "value". Genérico — cobre limites como "inimigos
/// fugidos &gt;= 3", "erros do puzzle &gt;= 2", etc., usando contadores já
/// mantidos por Action_IncrementIntVariable.
/// </summary>
[System.Serializable]
public class FailCondition_IntVariableThreshold : ChallengeFailCondition
{
    [Tooltip("Nome da variável global (GameVariables). Se não existir, é tratada como tendo o valor por omissão (0).")]
    public string variableName;

    [Tooltip("Como comparar o valor actual da variável com \"value\".")]
    public Comparison comparison = Comparison.GreaterOrEqual;

    public int value;

    public override bool IsFailed()
    {
        int actual = GameVariables.Instance != null ? GameVariables.Instance.GetInt(variableName) : 0;
        return NpcConditionUtil.Compare(actual, comparison, value);
    }
}
